INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Heaving_Snatch_Balance','Heaving Snatch Balance','cuádriceps',ARRAY['abdominales','antebrazos','glúteos','isquiotibiales','hombros','tríceps'],'barra','olympic weightlifting',ARRAY['This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with.','Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat.','Return to a standing position.'],'This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with. Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat. Return to a standing position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heaving_Snatch_Balance/0.jpg','exercisedb',true),('Heavy_Bag_Thrust','Heavy Bag Thrust','pecho',ARRAY['abdominales','hombros','tríceps'],'otro','plyometrics',ARRAY['Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position.','Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body.','Receive the bag as it swings back by reversing these steps.'],'Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position. Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body. Receive the bag as it swings back by reversing these steps.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heavy_Bag_Thrust/0.jpg','exercisedb',true),('High_Cable_Curls','High Cable Curls','bíceps',ARRAY[]::text[],'cable','strength',ARRAY['Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position.','Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps.','Slowly bring back the arms to the starting position.','Repeat for the recommended amount of repetitions.'],'Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position. Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps. Slowly bring back the arms to the starting position. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/High_Cable_Curls/0.jpg','exercisedb',true),('Hip_Circles_prone','Hip Circles (prone)','abductores',ARRAY['aductores'],'peso corporal','stretching',ARRAY['Position yourself on your hands and knees on the ground. Maintaining good posture, raise one bent knee off of the ground. This will be your starting position.','Keeping the knee in a bent position, rotate the femur in an arc, attempting to make a big circle with your knee.','Perform this slowly for a number of repetitions, and repeat on the other side.'],'Position yourself on your hands and knees on the ground. Maintaining good posture, raise one bent knee off of the ground. This will be your starting position. Keeping the knee in a bent position, rotate the femur in an arc, attempting to make a big circle with your knee. Perform this slowly for a number of repetitions, and repeat on the other side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Circles_prone/0.jpg','exercisedb',true),('Hip_Extension_with_Bands','Hip Extension with Bands','glúteos',ARRAY['isquiotibiales'],'bandas elásticas','strength',ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Facing the attachment point of the band, hold on to the column to stabilize yourself.','Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.','Return the leg to the starting position.'],'Secure one end of the band to the lower portion of a post and attach the other to one ankle. Facing the attachment point of the band, hold on to the column to stabilize yourself. Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight. Return the leg to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Extension_with_Bands/0.jpg','exercisedb',true),('Hip_Flexion_with_Band','Hip Flexion with Band','cuádriceps',ARRAY[]::text[],'bandas elásticas','strength',ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Face away from the attachment point of the band.','Keeping your head and your chest up, raise your knee up to 90 degrees and pause.','Return the leg to the starting position.'],'Secure one end of the band to the lower portion of a post and attach the other to one ankle. Face away from the attachment point of the band. Keeping your head and your chest up, raise your knee up to 90 degrees and pause. Return the leg to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Flexion_with_Band/0.jpg','exercisedb',true),('Hip_Lift_with_Band','Hip Lift with Band','glúteos',ARRAY['pantorrillas','isquiotibiales'],'bandas elásticas','powerlifting',ARRAY['After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn''''t have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won''''t move.','Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position.','Keeping your shoulders on the ground, drive through your heels to raise your hips, pushing into the band as high as you can.','Pause at the top of the motion, and return to the starting position.'],'After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn''t have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won''t move. Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position. Keeping your shoulders on the ground, drive through your heels to raise your hips, pushing into the band as high as you can. Pause at the top of the motion, and return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Lift_with_Band/0.jpg','exercisedb',true),('Hug_A_Ball','Hug A Ball','espalda baja',ARRAY['pantorrillas','glúteos'],'pelota de ejercicio','stretching',ARRAY['Seat yourself on the floor.','Straddle an exercise ball between both legs and lower your hips down toward the floor.','Hug your arms around the ball to support your body. Adjust your legs so that your feet are flat on the floor and your knees line up over your ankles. Keep a good grip on the ball so it doesn''''t roll away from you and send you back onto your buttocks.'],'Seat yourself on the floor. Straddle an exercise ball between both legs and lower your hips down toward the floor. Hug your arms around the ball to support your body. Adjust your legs so that your feet are flat on the floor and your knees line up over your ankles. Keep a good grip on the ball so it doesn''t roll away from you and send you back onto your buttocks.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_A_Ball/0.jpg','exercisedb',true),('Hug_Knees_To_Chest','Hug Knees To Chest','espalda baja',ARRAY['glúteos'],NULL,'stretching',ARRAY['Lie down on your back and pull both knees up to your chest.','Hold your arms under the knees, not over (that would put to much pressure on your knee joints).','Slowly pull the knees toward your shoulders. This also stretches your buttocks muscles.'],'Lie down on your back and pull both knees up to your chest. Hold your arms under the knees, not over (that would put to much pressure on your knee joints). Slowly pull the knees toward your shoulders. This also stretches your buttocks muscles.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_Knees_To_Chest/0.jpg','exercisedb',true),('Hurdle_Hops','Hurdle Hops','isquiotibiales',ARRAY['abductores','aductores','pantorrillas','glúteos','isquiotibiales'],'otro','plyometrics',ARRAY['Set up a row of hurdles or other small barriers, placing them a few feet apart.','Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position.','Begin by jumping with both feet over the first hurdle, swinging both arms as you jump.','Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next hurdle. Continue until you have jumped over all of the hurdles.'],'Set up a row of hurdles or other small barriers, placing them a few feet apart. Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position. Begin by jumping with both feet over the first hurdle, swinging both arms as you jump. Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next hurdle. Continue until you have jumped over all of the hurdles.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hurdle_Hops/0.jpg','exercisedb',true);